import { Component } from '@angular/core';
import { CommonModule } from '@angular/common'; 
import { FormsModule } from '@angular/forms';   

@Component({
  selector: 'app-home',
  standalone: true,
  imports: [CommonModule, FormsModule],
  templateUrl: './home.component.html',
  styleUrls: ['./home.component.scss']
})
export class HomeComponent {
  // كروت الخدمات الثلاثة كما تظهر في الصورة بالضبط
  services = [
    { title: 'PEDIATRICIANS' },
    { title: 'URANOLOGISTS' },
    { title: 'IMMUNOLOGISTS' }
  ];

  // تكرار الأطباء الـ 12 بنظام شبكي متقاطع متناسق
  doctors = Array(12).fill(null).map((_, index) => ({
    name: `Doctor M${index + 1}`,
    specialty: 'MBBS, MD'
  }));

  contactData = {
    firstName: '',
    lastName: '',
    mobileNumber: '',
    email: '',
    message: ''
  };

  // 1. تشغيل وبرمجة أزرار الصفحة الأساسية
  onNextClick() {
    alert('Hero "Next" button clicked successfully!');
  }

  onSeeMoreClick() {
    alert('About Us "See More" button clicked successfully!');
  }

  onPrevSlide() {
    console.log('Slider dot arrow navigated.');
  }

  onSubmit() {
    if (this.contactData.firstName && this.contactData.email) {
      alert(`Message sent successfully by: ${this.contactData.firstName}`);
      // مسح البيانات بعد الإرسال الناجح
      this.contactData = { firstName: '', lastName: '', mobileNumber: '', email: '', message: '' };
    }
  }
}
